/**
 * Helper class for Min-Heap implementation required for Dijkstra's algorithm.
 * Stores elements as [distance, node].
 */
class MinPriorityQueue {
    constructor() {
        this.heap = [];
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    size() {
        return this.heap.length;
    }

    // Inserts a new element [distance, node]
    enqueue(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    // Removes and returns the element with the minimum distance
    dequeue() {
        if (this.isEmpty()) return null;
        if (this.heap.length === 1) return this.heap.pop();

        const min = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.bubbleDown(0);
        return min;
    }

    bubbleUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            // Compare based on distance (the first element of the pair)
            if (this.heap[index][0] < this.heap[parentIndex][0]) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    bubbleDown(index) {
        const lastIndex = this.heap.length - 1;
        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let smallest = index;

            // Check left child
            if (leftChildIndex <= lastIndex && this.heap[leftChildIndex][0] < this.heap[smallest][0]) {
                smallest = leftChildIndex;
            }

            // Check right child
            if (rightChildIndex <= lastIndex && this.heap[rightChildIndex][0] < this.heap[smallest][0]) {
                smallest = rightChildIndex;
            }

            if (smallest !== index) {
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                index = smallest;
            } else {
                break;
            }
        }
    }
}


function solve(n, edges, source, target, k) {
    if (source === target) return 0;

    // 1. Build Adjacency List
    const adj = Array(n).fill(0).map(() => []);
    let maxWeight = 0;
    for (const [u, v, w] of edges) {
        adj[u].push({ node: v, weight: w });
        adj[v].push({ node: u, weight: w });
        maxWeight = Math.max(maxWeight, w);
    }

    /**
     * Checks if a path exists from source to target using at most k heavy edges,
     * given the current threshold.
     * @param {number} threshold The edge weight threshold.
     * @returns {boolean} True if a valid path exists, false otherwise.
     */
    const canReach = (threshold) => {
        // D[i] stores the minimum number of heavy edges required to reach node i.
        const INF = Infinity;
        const dist = Array(n).fill(INF);
        dist[source] = 0;

        // Priority Queue stores [heavy_edge_count, node]
        const pq = new MinPriorityQueue();
        pq.enqueue([0, source]);

        while (!pq.isEmpty()) {
            const [d, u] = pq.dequeue();

            if (d > dist[u]) {
                continue;
            }

            if (u === target) {
                // Optimization: If we reached target, we found the minimum heavy edge count.
                return d <= k;
            }

            for (const edge of adj[u]) {
                const v = edge.node;
                const w = edge.weight;

                // Cost is 1 if heavy (w > threshold), 0 otherwise.
                const cost = (w > threshold) ? 1 : 0;

                const newDist = d + cost;

                if (newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.enqueue([newDist, v]);
                }
            }
        }

        // After Dijkstra's finishes, check the target distance
        return dist[target] <= k;
    };

    // 2. Binary Search on the threshold [L, R]
    // Search space for threshold is [0, maxWeight].
    let L = 0;
    let R = maxWeight;
    let ans = -1;

    while (L <= R) {
        // Use floor division for Mid
        const Mid = Math.floor((L + R) / 2);

        if (canReach(Mid)) {
            // If it's possible with this threshold, Mid is a potential answer. Try smaller.
            ans = Mid;
            R = Mid - 1;
        } else {
            // If it's not possible, we need a larger threshold to potentially classify more edges as light.
            L = Mid + 1;
        }
    }

    return ans;
}

