        adj[v].push({ neighbor: u, weight: w }); // Undirected graph
    }

    // 2. can_reach function: Checks if target is reachable from source using at most k heavy edges
    const can_reach = (threshold) => {
        // D[u][h]: true if node u is reachable using exactly h heavy edges.
        // K is up to 1000, N up to 1000. O(N*K) space.
        const D = Array(n).fill(0).map(() => Array(k + 1).fill(false));

        // BFS Queue: stores [node_id, heavy_count]
        const queue = [];

        if (source === target) return true;

        D[source][0] = true;
        queue.push([source, 0]);

        let head = 0;
        while (head < queue.length) {
            const [u, h] = queue[head++];

