                const v = edge.neighbor;
                const w = edge.weight;

                // Cost: 1 if heavy (w > threshold), 0 otherwise
                const cost = (w > threshold) ? 1 : 0;

                const h_prime = h + cost;

                if (h_prime <= k && !D[v][h_prime]) {
                    if (v === target) {
                        return true;
                    }
                    D[v][h_prime] = true;
                    queue.push([v, h_prime]);
                }
            }
        }

        return false;
    };

    // 3. Binary Search on Threshold

    // Weights are 1 to 10^9. 
    // L=0: Lowest possible threshold (all edges with w>=1 are heavy if threshold is 0, except if weights were 0, but they are >= 1)
    let L = 0; 
    // R=10^9 + 1: Search space exclusive upper bound. If threshold >= 10^9, all edges are light.
    let R = 10**9 + 1; 

    let min_threshold = -1;

    while (L < R) {
        // M is the proposed threshold
        const M = Math.floor(L + (R - L) / 2);

        if (can_reach(M)) {
            // M works. Store it, try finding a smaller threshold.
            min_threshold = M;
            R = M; 
        } else {
