/**
 * @param {number} n The number of nodes.
 * @param {number[][]} edges The list of edges [u, v, w].
 * @param {number} source The starting node.
 * @param {number} target The destination node.
 * @param {number} k The maximum allowed heavy edges.
 * @return {number} The minimum threshold, or -1.
 */
function solve(n, edges, source, target, k) {

    if (source === target) {
        return 0;
    }

    // 1. Build Adjacency List
    const adj = Array(n).fill(0).map(() => []);
    let maxWeight = 0;

    for (const [u, v, w] of edges) {
        adj[u].push({ v: v, w: w });
        adj[v].push({ v: u, w: w });
        if (w > maxWeight) {
            maxWeight = w;
        }
    }

    /**
     * Checks if a path exists from source to target using at most k heavy edges
     * given a specific threshold.
     * @param {number} threshold 
     * @returns {boolean}
     */
    function canReach(threshold) {
        // minHeavy[i] stores the minimum number of heavy edges required to reach node i.
        const minHeavy = Array(n).fill(Infinity);
        minHeavy[source] = 0;

        // We use Dijkstra's algorithm. Since weights are 0 (light) or 1 (heavy), 
        // we simulate the priority queue by repeatedly finding the node with minimum heavy count.
        const visited = Array(n).fill(false);

        for (let i = 0; i < n; i++) {
            // 1. Find the unvisited node u with the minimum heavy count
            let minH = Infinity;
            let u = -1;

            for (let j = 0; j < n; j++) {
                if (!visited[j] && minHeavy[j] < minH) {
                    minH = minHeavy[j];
                    u = j;
                }
            }

            if (u === -1 || minHeavy[u] > k) {
                // No reachable unvisited nodes, or the best path exceeds k
                break;
            }

            visited[u] = true;

            if (u === target) {
                // Since we are using Dijkstra, the first time we extract target, 
                // we have found the minimum heavy path count.
                return true; // minHeavy[target] <= k is implicitly true here
            }

            // 2. Relax neighbors
            for (const edge of adj[u]) {
                const v = edge.v;
                const w = edge.w;

                // Cost c: 1 if heavy (w > threshold), 0 if light (w <= threshold)
                const c = (w > threshold) ? 1 : 0;

                const newHeavyCount = minHeavy[u] + c;

                if (newHeavyCount <= k && newHeavyCount < minHeavy[v]) {
                    minHeavy[v] = newHeavyCount;
                }
            }
        }

        return minHeavy[target] <= k;
    }


    // 2. Binary Search on the Threshold
    // Search range: [L, R]
    // L = 0 (Minimum possible threshold)
    // R = maxWeight + 1 (A threshold higher than maxWeight ensures all edges are light)

    let L = 0;
    let R = maxWeight + 1;
    let ans = -1;

    while (L < R) {
        // Use floor division equivalent for mid
        const Mid = Math.floor((L + R) / 2);

        if (canReach(Mid)) {
            // Possible answer found. Try for a smaller threshold.
            ans = Mid;
            R = Mid;
        } else {
            // Threshold is too small, need more flexibility (higher threshold).
            L = Mid + 1;
        }
    }

    return ans;
}
